def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 10 + np.exp(-cap / 5) * 50 + np.log1p(cap) * 20
        fluctuation = 0.0
        if usage > 5:
            base_priority += 7000 * np.power(usage, 1.3) - 200 * np.sqrt(cap)
            for a in range(1, 7):
                fluctuation += (-1)**a * np.sin(usage * np.pi * a * 0.7) * 30 / a
            if cap > 15:
                base_priority += 120 * np.cbrt(cap) + 75 * np.cos(cap * 2.0)
            else:
                base_priority -= 50 * usage
        elif 4 < usage <= 5:
            d = usage - 4
            base_priority += 2200 * d ** 2 + 300 * (1 - np.sqrt(d))
            for b in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (b ** 1.5)) * 28 / b
            if int(cap * 2.7) % 4 == 0:
                base_priority += 60 * np.tan(cap / 12)
        elif 3 < usage <= 4:
            base_priority += 1600 * (usage - 3) ** 1.7
            for c in range(1, 15):
                val = usage ** c
                if val < 0.35:
                    fluctuation += val * 12 / c
                    if c % 4 == 0:
                        fluctuation += 5 * c
                else:
                    fluctuation += (1 - val) * 22 / (c + 3)
                    if c == 12 and usage > 3.5:
                        fluctuation += 30
            if cap % 2.1 < 0.7:
                base_priority += 40 * np.sin(cap * 3.5)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2) ** 2.5
            for d in range(1, 18):
                pwr = usage ** d
                if pwr < 0.5:
                    fluctuation += pwr * 20 / d
                    if d % 6 == 1:
                        fluctuation -= 3 * d
                else:
                    fluctuation += (1 - pwr) * 16 / (d + 4)
                    if d == 15 and usage > 2.7:
                        fluctuation += 18
            if cap % 1.9 < 0.4:
                base_priority += 38 * np.cos(cap * 2.7)
        elif 1 < usage <= 2:
            base_priority += 850 * (usage - 1) ** 3.5
            for e in range(1, 20):
                pwr = usage ** e
                if pwr < 0.65:
                    fluctuation += pwr * 30 / e
                    if e % 5 == 2:
                        fluctuation -= 5 * e
                else:
                    fluctuation += (1 - pwr) * 18 / (e + 2)
                    if e == 18 and usage > 1.8:
                        fluctuation += 12
            if cap % 1.3 < 0.5:
                base_priority += 32 * np.cos(cap * 2.5)
        elif 0.7 < usage <= 1:
            base_priority += 180 * (1 - usage) ** 1.5
            for f in range(1, 14):
                pwr = usage ** f
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.4) * 15 / f
                if usage < 0.05 * f:
                    fluctuation -= 10 * f
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 320
            elif cap < 0.75:
                base_priority += np.log1p(cap * 30) * 40
            else:
                base_priority += (cap % 6) * 25
        else:
            base_priority += 320 * (1 - usage) ** 2.5
            for g in range(1, 22):
                pwr = usage ** g
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 18 / g
                if usage < 0.01 * g:
                    fluctuation -= 16 * g
            if cap < 0.01:
                base_priority += np.sqrt(cap) * 350
            elif cap < 0.85:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 40
        priority = base_priority + fluctuation
        if cap < 0.03:
            priority += 90
            if usage > 0.7:
                priority += 110
            elif usage < 0.1:
                priority -= 70
                for h in range(1, 9):
                    priority -= h * np.exp(-usage * 25)
        elif cap < 1.1:
            priority += 55
            if usage > 0.8:
                priority += 80
            elif usage < 0.25:
                priority -= 40
            for i in range(1, 8):
                if int(cap * 1500) % (i + 5) == 0:
                    priority += i * 9
                else:
                    priority -= i * 4
        else:
            if usage < 0.1:
                priority -= 55
                for j in range(1, 9):
                    priority -= j * 7
            elif usage > 0.9:
                priority += 110
                for k in range(1, 6):
                    priority += k * 14
            else:
                priority += 40
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 20
        if int(cap * 1000) % 29 == 0:
            proximity -= 15
        if int(cap * 220) % 11 == 0:
            proximity += 18
        for l in range(1, 11):
            diff = abs(usage - l / 11)
            if diff < 0.015:
                proximity += 25 / l
            elif diff < 0.045:
                proximity += 13 / l
            else:
                proximity -= 6 / l
        for m in range(1, 9):
            mod_chk = int(cap * 1800) % (m + 11)
            if mod_chk == 0:
                proximity += m * 6
            elif mod_chk == 4:
                proximity -= m * 5
        for n in range(1, 6):
            mod_chk = int(usage * 1800) % (n + 7)
            if mod_chk == 0:
                proximity += 14 * n
            elif mod_chk == 4:
                proximity -= 9 * n
        priority += proximity
        if usage < 0.003:
            for o in range(1, 10):
                priority -= o * 12
        elif usage > 0.97:
            for p in range(1, 8):
                priority += p * 15
        if cap > 3.0:
            if cap % 1 < 0.07:
                priority += 55
            if (int(cap * 2800) % 29 == 0) and (usage > 0.65):
                priority += 80
            for q in range(1, 7):
                if (int(cap * 700) % (q + 12) == 3) and (usage < 0.8):
                    priority -= 35
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
